import{d as s,A as d,c as i,p as e,b as n,o as c,B as v,C as f,y as l}from"./DF1aTxOJ.js";const r={class:"min-h-screen",style:{background:"var(--surface)"}},p=s({__name:"cookies",setup(g){return d({title:"Политика cookies — Bugaev Web",meta:[{name:"description",content:"Политика использования cookies на сайте Bugaev Web: какие cookies используем, для чего, как управлять ими через настройки браузера."},{name:"robots",content:"noindex, nofollow"}],link:[{rel:"canonical",href:"https://bugaev-web.ru/cookies"}]}),(k,a)=>{const t=v,o=f;return c(),i("div",r,[e(t),a[0]||(a[0]=n('<main class="pt-28 pb-20" data-v-7274fe52><div class="section-container" data-v-7274fe52><div class="mb-12" data-animate="fade-up" data-v-7274fe52><span class="badge mb-5" data-v-7274fe52>Юридический документ</span><h1 class="section-title mb-4" data-v-7274fe52>Политика<br data-v-7274fe52>использования cookies</h1><p class="section-subtitle max-w-xl" data-v-7274fe52> Информация о файлах cookie, используемых на сайте «Bugaev Web», их назначении и способах управления. </p></div><div class="h-px mb-12" style="background:var(--border);" data-v-7274fe52></div><div class="legal-body max-w-3xl" data-v-7274fe52><section class="legal-section" data-v-7274fe52><h2 data-v-7274fe52>1. Что такое cookies</h2><p data-v-7274fe52>1.1. Cookies (куки) — небольшие текстовые файлы, которые сайт сохраняет в браузере или на устройстве Пользователя при посещении сайта. Они позволяют сайту «запомнить» действия и настройки Пользователя на определённый период времени.</p><p data-v-7274fe52>1.2. Cookies не являются программами и не могут выполнять какой-либо код, поэтому они не представляют угрозы для безопасности устройства.</p><p data-v-7274fe52>1.3. Настоящая Политика регулирует использование cookies на сайте, принадлежащем ИП Бугаеву Дмитрию Сергеевичу (ОГРНИП 326645700031745), осуществляющему деятельность под коммерческим обозначением «Bugaev Web».</p></section><section class="legal-section" data-v-7274fe52><h2 data-v-7274fe52>2. Какие cookies мы используем</h2><h3 data-v-7274fe52>2.1. Строго необходимые (технические) cookies</h3><p data-v-7274fe52>Обязательны для корректной работы сайта. Без них сайт не сможет функционировать должным образом. Эти cookies не требуют согласия Пользователя.</p><ul data-v-7274fe52><li data-v-7274fe52><strong data-v-7274fe52>Сессионные cookies</strong> — хранятся в течение текущей сессии браузера и удаляются при его закрытии;</li><li data-v-7274fe52><strong data-v-7274fe52>Cookies безопасности</strong> — защита от CSRF-атак и иных угроз;</li><li data-v-7274fe52><strong data-v-7274fe52>Cookies состояния согласия</strong> — запоминают выбор Пользователя в отношении использования cookies, чтобы не спрашивать согласие при каждом посещении.</li></ul><h3 data-v-7274fe52>2.2. Функциональные cookies</h3><p data-v-7274fe52>Улучшают удобство использования сайта, запоминая предпочтения Пользователя (язык, настройки отображения). Используются только при согласии Пользователя.</p><h3 data-v-7274fe52>2.3. Аналитические cookies</h3><p data-v-7274fe52>Позволяют анализировать поведение посетителей сайта с целью улучшения его содержания и функциональности. Используем следующие инструменты:</p><ul data-v-7274fe52><li data-v-7274fe52><strong data-v-7274fe52>Яндекс.Метрика</strong> — собирает обезличенную статистику о посещениях, источниках трафика, поведении на сайте. Политика конфиденциальности Яндекса: <a href="https://yandex.ru/legal/confidential/" target="_blank" rel="noopener noreferrer" data-v-7274fe52>yandex.ru/legal/confidential</a>.</li></ul><p data-v-7274fe52>Аналитические cookies используются только при согласии Пользователя.</p><h3 data-v-7274fe52>2.4. Маркетинговые (рекламные) cookies</h3><p data-v-7274fe52>В настоящий момент маркетинговые cookies на сайте не используются. При введении таких cookies Политика будет обновлена.</p></section><section class="legal-section" data-v-7274fe52><h2 data-v-7274fe52>3. Срок хранения cookies</h2><table class="req-table" data-v-7274fe52><thead data-v-7274fe52><tr data-v-7274fe52><th data-v-7274fe52>Категория</th><th data-v-7274fe52>Срок хранения</th></tr></thead><tbody data-v-7274fe52><tr data-v-7274fe52><td data-v-7274fe52>Сессионные (технические)</td><td data-v-7274fe52>До закрытия браузера</td></tr><tr data-v-7274fe52><td data-v-7274fe52>Постоянные технические</td><td data-v-7274fe52>До 1 года</td></tr><tr data-v-7274fe52><td data-v-7274fe52>Cookies согласия</td><td data-v-7274fe52>До 1 года</td></tr><tr data-v-7274fe52><td data-v-7274fe52>Аналитические (Яндекс.Метрика)</td><td data-v-7274fe52>До 1 года</td></tr></tbody></table></section><section class="legal-section" data-v-7274fe52><h2 data-v-7274fe52>4. Согласие на использование cookies</h2><p data-v-7274fe52>4.1. При первом посещении сайта отображается уведомление (баннер), предлагающее принять или отклонить нетехнические cookies.</p><p data-v-7274fe52>4.2. Принятие всех cookies, кроме строго необходимых, является добровольным.</p><p data-v-7274fe52>4.3. Ваш выбор сохраняется в техническом cookie «cookie-consent» и не запрашивается повторно в течение 1 года.</p></section><section class="legal-section" data-v-7274fe52><h2 data-v-7274fe52>5. Как управлять cookies</h2><p data-v-7274fe52>5.1. <strong data-v-7274fe52>Через настройки браузера.</strong> Большинство браузеров позволяют управлять cookies через настройки. Вы можете блокировать или удалять cookies:</p><ul data-v-7274fe52><li data-v-7274fe52><strong data-v-7274fe52>Google Chrome:</strong> Настройки → Конфиденциальность и безопасность → Файлы cookie</li><li data-v-7274fe52><strong data-v-7274fe52>Mozilla Firefox:</strong> Настройки → Приватность и защита → Куки и данные сайтов</li><li data-v-7274fe52><strong data-v-7274fe52>Safari:</strong> Настройки → Конфиденциальность → Управление данными сайтов</li><li data-v-7274fe52><strong data-v-7274fe52>Яндекс.Браузер:</strong> Настройки → Сайты → Расширенные настройки → Cookie</li></ul><p data-v-7274fe52>5.2. Обратите внимание: блокировка строго необходимых cookies может нарушить работу сайта.</p><p data-v-7274fe52>5.3. <strong data-v-7274fe52>Отказ от аналитики Яндекс.Метрики</strong> возможен через официальный инструмент: <a href="https://yandex.ru/support/metrica/general/opt-out.html" target="_blank" rel="noopener noreferrer" data-v-7274fe52>yandex.ru/support/metrica/general/opt-out.html</a>.</p></section><section class="legal-section" data-v-7274fe52><h2 data-v-7274fe52>6. Передача данных cookies третьим лицам</h2><p data-v-7274fe52>6.1. Данные аналитических cookies передаются сервисам аналитики (Яндекс.Метрика) в обезличенном или агрегированном виде. Оператор не продаёт и не передаёт cookie-данные в коммерческих целях.</p><p data-v-7274fe52>6.2. При использовании встроенных виджетов и кнопок социальных сетей (Telegram и т.п.) эти сервисы могут устанавливать собственные cookies в соответствии с их политиками конфиденциальности.</p></section><section class="legal-section" data-v-7274fe52><h2 data-v-7274fe52>7. Изменение политики</h2><p data-v-7274fe52>7.1. Оператор вправе обновлять настоящую Политику в одностороннем порядке. Актуальная версия публикуется на сайте по адресу <strong data-v-7274fe52>/cookies</strong> с указанием даты последнего обновления.</p></section><section class="legal-section" data-v-7274fe52><h2 data-v-7274fe52>8. Контакты</h2><p data-v-7274fe52>По вопросам, связанным с использованием cookies, обращайтесь:</p><p data-v-7274fe52> Email: <a href="mailto:dmnbugaev@gmail.com" data-v-7274fe52>dmnbugaev@gmail.com</a><br data-v-7274fe52> Telegram: <a href="https://t.me/bugaev_web" target="_blank" rel="noopener noreferrer" data-v-7274fe52>@bugaev_web</a></p></section><div class="legal-updated" data-v-7274fe52> Редакция документа: март 2026 г. Дата последнего обновления: 24.03.2026 </div></div></div></main>',1)),e(o)])}}}),m=l(p,[["__scopeId","data-v-7274fe52"]]);export{m as default};
